@Composable
fun ChatScreen(viewModel: ChatViewModel) {
    Column {
        Header(title = "AI Chat")
        StreamingResponse(responseFlow = viewModel.response)
        InputField(onSend = { viewModel.send(it) })
    }
}

@Composable
fun StreamingResponse(responseFlow: StateFlow<String>) {
    val text by responseFlow.collectAsState()
    BasicText(
        text = text,
        style = TextStyle(fontSize = 16.sp)
    )
}

